import{_ as e,o as l,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F14_負債結構與償債壓力測試.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F14_負債結構與償債壓力測試.md"}'),i={name:"審計報告庫/財務審計/6261_久元/20260512/F14_負債結構與償債壓力測試.md"};function o(n,a,h,s,d,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="f14-負債結構與償債壓力測試-財務審計專家報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 財務審計專家報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-財務審計專家報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債結構是否健康？短期與長期的償債壓力是否可控？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債率17.6%短借0.14億無長借。流動比358%速動比259%ICR 15.5倍。償債風險零唯現金14.2億持續下降需關注</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2025年合併資產負債表</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：負債率17.6%無長借短借僅0.14億。流動比358%速動比259%ICR 15.5倍。現金14.2億vs總負債14.6億現金幾可全額覆蓋。利息支出0.07億持續遞減。各項償債指標優於製造業安全線。唯現金3年-46%從26.4→14.2億趨勢需關注。現金/負債比從190%降至97%。</li><li><strong>診斷見解</strong>：償債能力為所有題項中最強一環，各項指標在極端情境下也無違約風險，但現金儲備持續消耗且零借款策略在擴產階段未必最適，融資彈性雖大但若不及時動用可導致資金緊張。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="負債結構" tabindex="-1">負債結構 <a class="header-anchor" href="#負債結構" aria-label="Permalink to &quot;負債結構&quot;">​</a></h3><p>總負債14.58億中流動11.79億(81%)+非流動2.79億(19%)。短借僅0.14億無長借無公司債。結構極簡僅營運+租賃負債。零借款正被CapEx挑戰但負債率升至30%仍遠低京元~45%。</p><h3 id="償債壓力測試" tabindex="-1">償債壓力測試 <a class="header-anchor" href="#償債壓力測試" aria-label="Permalink to &quot;償債壓力測試&quot;">​</a></h3><p>情境一(營收-20%)：OP約2.6億ICR&gt;30倍。情境二(營收-30%至29億)：接近損平仍可付息。無違約風險。真正風險在流動性—CapEx+股利持續消耗，2027年現金恐降至5-8億。</p><h3 id="融資彈性" tabindex="-1">融資彈性 <a class="header-anchor" href="#融資彈性" aria-label="Permalink to &quot;融資彈性&quot;">​</a></h3><p>負債率17.6%同業最低(京元45%精測35%)，可容納新借款10-14億。適度舉債3-5億取代現金儲備更合理。流動比358%遠優安全線200%。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>現金3年-46%，若無節制2027年恐跌破10億(仍安全但無緩衝餘裕)，現金消耗過速為潛在流動性風險</li><li>零借款未必最優—低利率環境不使用槓桿可能錯失成長機會，被迫在擴產與配息間取捨，資金配置效率低落存利空</li><li>租賃負債2.79億年租金本息約2,800萬為剛性支出，雖規模小但亦為現金流出壓力之一</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>各項償債指標優於製造業同業，極端情境也無違約風險</li><li>負債率17.6%可容納10-14億新借款而不影響評級，融資彈性極大</li><li>利息支出0.07億持續遞減，即使舉債5億(利率3%)年利息僅0.15億EPS影響&lt;0.12元</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>償債能力為所有題項中最強一環。風險不在償債而在資金配置效率—過度保守使股東權益報酬率偏低。管理層已透過積極CapEx改變但需在保守與槓桿間取得平衡。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>原始數據：FinMind TaiwanStockBalanceSheet</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const b=e(i,[["render",o]]);export{_ as __pageData,b as default};
